<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8" />
  <meta name="viewport" content="width=device-width, initial-scale=1.0"/>
  <title>WastedToken Mint | Collectible Challenge Coins</title>
  <style>
    :root {
      --bg-dark: #0f0f13;
      --text-light: #e8e8ed;
      --accent-gold: #ffd700;
      --accent-silver: #c0c0c0;
      --accent-bronze: #cd7f32;
      --accent-black: #1a1a1a;
      --coin-shadow: rgba(0, 0, 0, 0.6);
    }

    * {
      box-sizing: border-box;
      margin: 0;
      padding: 0;
    }

    body {
      font-family: 'Courier New', monospace;
      background-color: var(--bg-dark);
      color: var(--text-light);
      line-height: 1.6;
      overflow-x: hidden;
    }

    /* Hero Section */
    .hero-section {
      position: relative;
      min-height: 80vh;
