      -webkit-background-clip: text;
      background-clip: text;
      color: transparent;
      font-weight: bold;
      letter-spacing: 2px;
    }

    .coin-container {
      position: relative;
      width: clamp(300px, 60vw, 500px);
      height: clamp(300px, 60vw, 500px);
