    .hero-subtitle {
      margin-top: 3rem;
      font-size: clamp(1.2rem, 2vw, 1.8rem);
      text-align: center;
      max-width: 700px;
      opacity: 0.9;
    }

    /* About Section */
    .about-section {
      padding: 5rem 1rem;
      background-color: #14141a;
      text-align: center;
    }

    .section-title {
      font-size: clamp(2rem, 4vw, 3.5rem);
      margin-bottom: 2rem;
      color: var(--accent-gold);
    }

    .about-content {
      max-width: 800px;
      margin: 0 auto;
      font-size: clamp(1rem, 1.8vw, 1.4rem);
