    </div>
  </section>

  <section class="editions-section">
    <h2 class="section-title">Signature Editions</h2>

    <div class="edition-grid">
      <!-- Bronze Edition -->
      <div class="edition" data-edition="bronze" data-state="available">
        <div class="edition-canvas-container">
          <canvas class="edition-canvas"></canvas>
        </div>
        <div class="edition-info">
