      </div>

      <!-- Silver Edition -->
      <div class="edition" data-edition="silver" data-state="available">
        <div class="edition-canvas-container">
          <canvas class="edition-canvas"></canvas>
        </div>
        <div class="edition-info">
          <h3 class="edition-name">Silver Edition</h3>
          <span class="edition-state state-available">Available</span>
          <button class="buy">Add to cart</button>
        </div>
      </div>

      <!-- Gold Edition -->
      <div class="edition" data-edition="gold" data-state="sold-out">
        <div class="edition-canvas-container">
          <canvas class="edition-canvas"></canvas>
        </div>
        <div class="edition-info">
          <h3 class="edition-name">Gold Edition</h3>
          <span class="edition-state state-sold-out">SOLD OUT</span>
        </div>
      </div>

      <!-- Black Obsidian Edition -->
      <div class="edition" data-edition="black" data-state="coming-soon">
        <div class="edition-canvas-container">
          <canvas class="edition-canvas"></canvas>
        </div>
        <div class="edition-info">
          <h3 class="edition-name">Black Obsidian Edition</h3>
          <span class="edition-state state-coming-soon">Minting Next Season: Winter</span>
        </div>
      </div>
    </div>
  </section>

  <footer>
    <p class="footer-text">&copy; 2025 WastedToken Mint. All rights reserved.</p>
  </footer>

  <script>
    // ==========================================
    // HERO COIN RENDERER
    // ==========================================

    const coinCanvas = document.getElementById('coin-hero');
    const ctx = coinCanvas.getContext('2d');

    // Set canvas resolution for high-DPI displays
    function resizeCoinCanvas() {
      const size = Math.min(window.innerWidth * 0.9, 600);
      const dpr = window.devicePixelRatio || 1;

      coinCanvas.width = size * dpr;
      coinCanvas.height = size * dpr;
      ctx.scale(dpr, dpr);
    }

    resizeCoinCanvas();
    window.addEventListener('resize', () => {
      resizeCoinCanvas();
      if (!window.demo.paused) {
        window.demo.pause(); // Pause on resize to avoid animation glitches
      }
    });

    // Coin rendering state
    let coinRotation = 0;
    let coinTilt = 0;
    let time = 0;

    // Helper functions for procedural drawing
    function drawReededEdge(ctx, centerX, centerY, radius) {
      const numRidges = 48;
      const ridgeWidth = (Math.PI * 2) / numRidges;

      ctx.save();
      ctx.translate(centerX, centerY);

      for (let i = 0; i < numRidges; i++) {
        ctx.beginPath();
        ctx.moveTo(0, 0);
        ctx.arc(0, 0, radius, i * ridgeWidth, (i + 1) * ridgeWidth);
        ctx.closePath();

        // Create gradient for reeding
        const grad = ctx.createLinearGradient(
          Math.cos(i * ridgeWidth + ridgeWidth/2) * radius,
          Math.sin(i * ridgeWidth + ridgeWidth/2) * radius,
          Math.cos(i * ridgeWidth + ridgeWidth/2) * (radius - 5),
          Math.sin(i * ridgeWidth + ridgeWidth/2) * (radius - 5)
        );

        grad.addColorStop(0, '#b8860b');
        grad.addColorStop(0.5, '#ffd700');
        grad.addColorStop(1, '#b8860b');

        ctx.fillStyle = grad;
        ctx.fill();
      }

      // Add inner reeding ring
      ctx.beginPath();
      ctx.arc(0, 0, radius - 2, 0, Math.PI * 2);
      ctx.strokeStyle = '#ffd700';
      ctx.lineWidth = 1;
      ctx.stroke();

      ctx.restore();
    }

    function drawEmbossedText(ctx, text, x, y, fontSize, fontWeight) {
      // Create embossed effect using multiple shadows
      ctx.font = `${fontWeight} ${fontSize}px 'Courier New', monospace`;
      ctx.textAlign = 'center';
      ctx.textBaseline = 'middle';

      // Shadow for depth
      ctx.fillStyle = '#000000';
      ctx.shadowColor = 'rgba(0, 0, 0, 0.8)';
      ctx.shadowBlur = 4;
      ctx.fillText(text, x + 2, y + 2);

      // Highlight for raised effect
      ctx.shadowBlur = 0;
      ctx.fillStyle = '#ffffff';
      ctx.fillText(text, x, y);
    }

    function drawWastedTokenLogo(ctx, centerX, centerY) {
      const radius = 140;

      // Outer circle
      ctx.beginPath();
      ctx.arc(centerX, centerY, radius, 0, Math.PI * 2);
      ctx.fillStyle = '#ffd700';
      ctx.fill();

      // Inner design elements
      ctx.save();
      ctx.translate(centerX, centerY);

      // Draw "WTM" in stylized font
      ctx.font = 'bold 60px Courier New';
      ctx.textAlign = 'center';
      ctx.textBaseline = 'middle';

      // Create gradient for text
      const grad = ctx.createLinearGradient(-50, -30, 50, 30);
      grad.addColorStop(0, '#b8860b');
      grad.addColorStop(0.5, '#ffd700');
      grad.addColorStop(1, '#b8860b');

      ctx.fillStyle = grad;

      // Add embossed effect
      ctx.shadowColor = 'rgba(0, 0, 0, 0.6)';
      ctx.shadowBlur = 4;
      ctx.fillText('WTM', 0, 5);

      // Decorative elements around the text
      for (let i = 0; i < 8; i++) {
        const angle = (i / 8) * Math.PI * 2;
        const x = Math.cos(angle) * radius;
        const y = Math.sin(angle) * radius;

        ctx.beginPath();
        ctx.arc(x, y, 6, 0, Math.PI * 2);
        ctx.fillStyle = '#ffd700';
        ctx.fill();

        // Add small dots between the main elements
        if (i % 2 === 0) {
          const innerAngle = angle + (Math.PI / 8);
          const innerX = Math.cos(innerAngle) * (radius - 30);
          const innerY = Math.sin(innerAngle) * (radius - 30);

          ctx.beginPath();
          ctx.arc(innerX, innerY, 3, 0, Math.PI * 2);
          ctx.fillStyle = '#b8860b';
          ctx.fill();
        }
      }

      // Add token symbol in center
      ctx.beginPath();
      ctx.arc(0, 50, 15, 0, Math.PI * 2);
      ctx.strokeStyle = '#ffd700';
      ctx.lineWidth = 3;
      ctx.stroke();

      ctx.restore();
    }

    function drawDenomination(ctx, centerX, centerY) {
      const radius = 140;

      // Background circle
      ctx.beginPath();
      ctx.arc(centerX, centerY, radius, 0, Math.PI * 2);
      ctx.fillStyle = '#c0c0c0';
      ctx.fill();

      // Create gradient for text
      const grad = ctx.createLinearGradient(-60, -30, 60, 30);
      grad.addColorStop(0, '#808080');
      grad.addColorStop(0.5, '#ffffff');
      grad.addColorStop(1, '#808080');

      ctx.save();
      ctx.translate(centerX, centerY);

      // Draw "10,000 TOKENS"
      ctx.font = 'bold 32px Courier New';
      ctx.textAlign = 'center';
      ctx.textBaseline = 'middle';

      ctx.fillStyle = grad;

      // Add embossed effect
      ctx.shadowColor = 'rgba(0, 0, 0, 0.6)';
      ctx.shadowBlur = 4;
      ctx.fillText('10,000 TOKENS', 0, -20);

      // Draw token symbol below
      ctx.beginPath();
      ctx.arc(0, 35, 20, 0, Math.PI * 2);
      ctx.strokeStyle = '#c0c0c0';
      ctx.lineWidth = 4;
      ctx.stroke();

      // Add inner circle to token symbol
      ctx.beginPath();
      ctx.arc(0, 35, 10, 0, Math.PI * 2);
      ctx.fillStyle = '#ffffff';
      ctx.fill();

      // Add decorative ring around the coin
      ctx.beginPath();
      ctx.arc(0, 0, radius - 10, 0, Math.PI * 2);
      ctx.strokeStyle = '#a9a9a9';
      ctx.lineWidth = 2;
      ctx.stroke();

      ctx.restore();
    }

    function drawCoinFace(ctx, centerX, centerY, faceType) {
      if (faceType === 'front') {
        drawWastedTokenLogo(ctx, centerX, centerY);
      } else {
        drawDenomination(ctx, centerX, centerY);
      }
    }

    // Main coin rendering function
    function renderCoin(time) {
      const width = coinCanvas.width / window.devicePixelRatio;
      const height = coinCanvas.height / window.devicePixelRatio;

      ctx.clearRect(0, 0, width, height);

      // Calculate rotation and tilt based on time
      const rotation = (time % 1) * Math.PI * 2; // Full rotation
      const tilt = Math.sin(time * Math.PI * 2) * 0.5; // Tilt between -0.5 and 0.5 radians

      ctx.save();

      // Center the coin in canvas
      const centerX = width / 2;
      const centerY = height / 2;
      const radius = Math.min(width, height) * 0.35;

      // Move to center for transformations
      ctx.translate(centerX, centerY);

      // Apply rotation and tilt
      ctx.rotate(rotation);
      ctx.rotateX(tilt); // This will be handled by our custom projection

      // Draw reeded edge (visible when tilted)
      if (Math.abs(tilt) > 0.1) {
        drawReededEdge(ctx, 0, 0, radius);
      }

      // Determine which face to show based on rotation
      const frontFaceVisible = Math.cos(rotation) > 0;

      // Create gradient for metallic effect
      const coinGradient = ctx.createRadialGradient(
        -radius * 0.3, -radius * 0.3, radius * 0.1,
        0, 0, radius
      );

      if (frontFaceVisible) {
        // Front face: Gold
        coinGradient.addColorStop(0, '#ffd700');
        coinGradient.addColorStop(0.5, '#b8860b');
        coinGradient.addColorStop(1, '#daa520');

        ctx.save();
        ctx.beginPath();
        ctx.arc(0, 0, radius, 0, Math.PI * 2);
        ctx.clip();

        // Draw the face
        drawCoinFace(ctx, 0, 0, 'front');

        // Add specular highlight that moves with rotation
        const highlightX = -Math.cos(rotation) * radius * 0.7;
        const highlightY = -Math.sin(rotation) * radius * 0.7;

        ctx.beginPath();
        ctx.arc(highlightX, highlightY, radius * 0.25, 0, Math.PI * 2);
        const highlightGrad = ctx.createRadialGradient(
          highlightX, highlightY, 0,
          highlightX, highlightY, radius * 0.25
        );
        highlightGrad.addColorStop(0, 'rgba(255, 255, 255, 0.8)');
        highlightGrad.addColorStop(1, 'rgba(255, 255, 255, 0)');

        ctx.fillStyle = highlightGrad;
        ctx.fill();

        // Add rim
        ctx.beginPath();
        ctx.arc(0, 0, radius - 2, 0, Math.PI * 2);
        ctx.strokeStyle = '#ffd700';
        ctx.lineWidth = 3;
        ctx.stroke();

        ctx.restore();
      } else {
        // Back face: Silver (slightly darker due to perspective)
        coinGradient.addColorStop(0, '#e8e8e8');
        coinGradient.addColorStop(0.5, '#c0c0c0');
        coinGradient.addColorStop(1, '#a9a9a9');

        ctx.save();
        ctx.beginPath();
        ctx.arc(0, 0, radius, 0, Math.PI * 2);
        ctx.clip();

        // Draw the face
        drawCoinFace(ctx, 0, 0, 'back');

        // Add specular highlight that moves with rotation
        const highlightX = -Math.cos(rotation) * radius * 0.7;
        const highlightY = -Math.sin(rotation) * radius * 0.7;

        ctx.beginPath();
        ctx.arc(highlightX, highlightY, radius * 0.25, 0, Math.PI * 2);
        const highlightGrad = ctx.createRadialGradient(
          highlightX, highlightY, 0,
          highlightX, highlightY, radius * 0.25
        );
        highlightGrad.addColorStop(0, 'rgba(255, 255, 255, 0.7)');
        highlightGrad.addColorStop(1, 'rgba(255, 255, 255, 0)');

        ctx.fillStyle = highlightGrad;
        ctx.fill();

        // Add rim
        ctx.beginPath();
        ctx.arc(0, 0, radius - 2, 0, Math.PI * 2);
        ctx.strokeStyle = '#c0c0c0';
        ctx.lineWidth = 3;
        ctx.stroke();

        ctx.restore();
      }

      // Add shadow for depth effect
      if (Math.abs(tilt) > 0.1) {
        ctx.save();
        ctx.rotate(-rotation); // Counter-rotate to keep shadow upright

        const shadowGradient = ctx.createRadialGradient(
          radius * 0.3, radius * 0.3, 0,
          radius * 0.3, radius * 0.3, radius
        );
        shadowGradient.addColorStop(0, 'rgba(0, 0, 0, 0.4)');
        shadowGradient.addColorStop(1, 'rgba(0, 0, 0, 0)');

        ctx.fillStyle = shadowGradient;
        ctx.beginPath();
        ctx.arc(radius * 0.3, radius * 0.3, radius, 0, Math.PI * 2);
        ctx.fill();

        ctx.restore();
      }

      ctx.restore();
    }

    // Animation loop
    let animationId;
    let isPaused = false;

    function animate() {
      if (!isPaused) {
        time += 0.01; // Adjust speed here
        renderCoin(time);
      }
      animationId = requestAnimationFrame(animate);
    }

    // Start the animation
    animate();

    // ==========================================
    // EDITION CANVAS RENDERERS
    // ==========================================

    function createEditionCanvas(designType) {
      const canvas = document.createElement('canvas');
      canvas.width = 400;
      canvas.height = 400;
      const ctx = canvas.getContext('2d');

      // Background gradient based on edition type
      let bgGradient;
      if (designType === 'bronze') {
        bgGradient = ctx.createRadialGradient(150, 150, 30, 200, 200, 200);
        bgGradient.addColorStop(0, '#cd7f32');
        bgGradient.addColorStop(0.5, '#8b4513');
        bgGradient.addColorStop(1, '#a0522d');
      } else if (designType === 'silver') {
        bgGradient = ctx.createRadialGradient(150, 150, 30, 200, 200, 200);
        bgGradient.addColorStop(0, '#c0c0c0');
        bgGradient.addColorStop(0.5, '#808080');
        bgGradient.addColorStop(1, '#a9a9a9');
      } else if (designType === 'gold') {
        bgGradient = ctx.createRadialGradient(150, 150, 30, 200, 200, 200);
        bgGradient.addColorStop(0, '#ffd700');
        bgGradient.addColorStop(0.5, '#daa520');
        bgGradient.addColorStop(1, '#b8860b');
      } else if (designType === 'black') {
        bgGradient = ctx.createRadialGradient(150, 150, 30, 200, 200, 200);
        bgGradient.addColorStop(0, '#1a1a1a');
        bgGradient.addColorStop(0.5, '#0d0d0d');
        bgGradient.addColorStop(1, '#000000');
      }

      // Draw coin background
      ctx.beginPath();
      ctx.arc(200, 200, 180, 0, Math.PI * 2);
      ctx.fillStyle = bgGradient;
      ctx.fill();

      // Add reeded edge effect
      const numRidges = 36;
      for (let i = 0; i < numRidges; i++) {
        const angle = (i / numRidges) * Math.PI * 2;
        const x1 = 200 + Math.cos(angle) * 180;
        const y1 = 200 + Math.sin(angle) * 180;
        const x2 = 200 + Math.cos(angle) * 175;
        const y2 = 200 + Math.sin(angle) * 175;

        ctx.beginPath();
        ctx.moveTo(x1, y1);
        ctx.lineTo(x2, y2);
        ctx.strokeStyle = 'rgba(255, 255, 255, 0.3)';
        ctx.lineWidth = 2;
        ctx.stroke();
      }

      // Draw design elements
      if (designType === 'bronze') {
        drawWastedTokenLogo(ctx, 200, 200);
      } else if (designType === 'silver') {
        drawDenomination(ctx, 200, 200);
      } else if (designType === 'gold') {
        // Gold version with special design
        ctx.beginPath();
        ctx.arc(200, 200, 160, 0, Math.PI * 2);
        ctx.fillStyle = '#ffd700';
        ctx.fill();

        ctx.font = 'bold 50px Courier New';
        ctx.textAlign = 'center';
        ctx.textBaseline = 'middle';

        const grad = ctx.createLinearGradient(150, 180, 250, 220);
        grad.addColorStop(0, '#b8860b');
        grad.addColorStop(0.5, '#ffd700');
        grad.addColorStop(1, '#daa520');

        ctx.fillStyle = grad;
        ctx.fillText('WTM', 200, 200);

        // Add special gold details
        for (let i = 0; i < 6; i++) {
          const angle = (i / 6) * Math.PI * 2;
          const x = 200 + Math.cos(angle) * 140;
          const y = 200 + Math.sin(angle) * 140;

          ctx.beginPath();
          ctx.arc(x, y, 8, 0, Math.PI * 2);
          ctx.fillStyle = '#ffd700';
          ctx.fill();

          // Add star shape
          if (i % 2 === 0) {
            drawStar(ctx, x, y, 5, 10, 5);
          }
        }

        // Add rim
        ctx.beginPath();
        ctx.arc(200, 200, 178, 0, Math.PI * 2);
        ctx.strokeStyle = '#ffd700';
        ctx.lineWidth = 4;
        ctx.stroke();

      } else if (designType === 'black') {
        // Black obsidian design
        ctx.beginPath();
        ctx.arc(200, 200, 160, 0, Math.PI * 2);
        ctx.fillStyle = '#1a1a1a';
        ctx.fill();

        // Add iridescent effect
        const grad = ctx.createLinearGradient(150, 180, 250, 220);
        grad.addColorStop(0, '#000000');
        grad.addColorStop(0.5, '#3a3a3a');
        grad.addColorStop(1, '#000000');

        ctx.fillStyle = grad;
        ctx.fillText('WTM', 200, 200);

        // Add obsidian details
        for (let i = 0; i < 8; i++) {
          const angle = (i / 8) * Math.PI * 2;
          const x = 200 + Math.cos(angle) * 140;
          const y = 200 + Math.sin(angle) * 140;

          ctx.beginPath();
          ctx.arc(x, y, 5, 0, Math.PI * 2);
          ctx.fillStyle = '#3a3a3a';
          ctx.fill();

          // Add diamond shape
          if (i % 2 === 0) {
            drawDiamond(ctx, x, y, 12, 8);
          }
        }

        // Add rim
        ctx.beginPath();
        ctx.arc(200, 200, 178, 0, Math.PI * 2);
        ctx.strokeStyle = '#3a3a3a';
        ctx.lineWidth = 4;
        ctx.stroke();

        // Add iridescent sheen
        const sheenGrad = ctx.createLinearGradient(150, 150, 250, 250);
        sheenGrad.addColorStop(0, 'rgba(255, 255, 255, 0.1)');
        sheenGrad.addColorStop(0.5, 'rgba(255, 255, 255, 0.3)');
        sheenGrad.addColorStop(1, 'rgba(255, 255, 255, 0.1)');

        ctx.fillStyle = sheenGrad;
        ctx.beginPath();
        ctx.arc(200, 200, 178, Math.PI * 0.2, Math.PI * 0.8);
        ctx.fill();
      }

      return canvas;
    }

    function drawStar(ctx, x, y, points, outerRadius, innerRadius) {
      const step = Math.PI / points;
      let rot = Math.PI / 2 * 3;
      ctx.beginPath();
      ctx.moveTo(x, y - outerRadius);

      for (let i = 0; i < points; i++) {
        const x1 = x + Math.cos(rot) * outerRadius;
        const y1 = y + Math.sin(rot) * outerRadius;
        ctx.lineTo(x1, y1);

        rot += step;

        const x2 = x + Math.cos(rot) * innerRadius;
        const y2 = y + Math.sin(rot) * innerRadius;
        ctx.lineTo(x2, y2);

        rot += step;
      }

      ctx.lineTo(x, y - outerRadius);
      ctx.closePath();
      ctx.fillStyle = 'rgba(255, 215, 0, 0.8)';
      ctx.fill();
    }

    function drawDiamond(ctx, x, y, width, height) {
      ctx.beginPath();
      ctx.moveTo(x, y - height/2);
      ctx.lineTo(x + width/2, y);
      ctx.lineTo(x, y + height/2);
      ctx.lineTo(x - width/2, y);
      ctx.closePath();
      ctx.fillStyle = 'rgba(192, 192, 192, 0.6)';
      ctx.fill();
    }

    // Initialize edition canvases
    const editionCanvases = document.querySelectorAll('.edition-canvas');

    const designTypes = ['bronze', 'silver', 'gold', 'black'];

    editionCanvases.forEach((canvas, index) => {
      if (index < designTypes.length) {
        canvas.appendChild(createEditionCanvas(designTypes[index]));
      }
